    >>> largest_prime_factor(13195)
    29
    >>> largest_prime_factor(2048)
    2
    """
    if is_prime(n):
        return n
    if is_even(n):
        return 2
    if is_even(n):
        return n - 1
    if is_even(n):
        return n - 2

    factor = n // 3 + 1

    while not is_prime(factor):
        factor -= 2

    return factor

