        return 0
    elif len(lst) == 1:
        if lst[0] % 2 == 0:
            return lst[0]
        else:
            return 0
    elif len(lst) == 2:
        if lst[0] % 2 == 0 and lst[1] % 2!= 0:
            return lst[0]
        elif lst[0] % 2!= 0 and lst[1] % 2 == 0:
            return lst[1]
        else:
            return 0
    else:
        if lst[0] % 2 == 0:
            return lst[0] + add(lst[1:])
        else:
            return add(lst[2:])
